import functions_framework
from flask import jsonify, request
import os
import json

@functions_framework.http
def api_endpoint(request):
    # Enable CORS
    headers = {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, Authorization'
    }
    
    # Handle preflight requests
    if request.method == 'OPTIONS':
        return ('', 204, headers)
    
    # Set default response headers
    response_headers = headers.copy()
    response_headers['Content-Type'] = 'application/json'
    
    try:
        # Validate request method
        if request.method not in ['GET', 'POST', 'PUT', 'DELETE']:
            return jsonify({'error': 'Method not allowed'}), 405, response_headers
        
        # Validate content type for POST/PUT requests
        if request.method in ['POST', 'PUT']:
            if not request.is_json:
                return jsonify({'error': 'Content-Type must be application/json'}), 400, response_headers
        
        # Process request based on method
        if request.method == 'GET':
            # Handle GET request
            data = {'message': 'GET request processed successfully'}
            return jsonify(data), 200, response_headers
            
        elif request.method == 'POST':
            # Handle POST request
            request_data = request.get_json(silent=True)
            if request_data is None:
                return jsonify({'error': 'Invalid JSON data'}), 400, response_headers
            
            # Validate required fields
            # Add your validation logic here
            
            data = {'message': 'POST request processed successfully', 'received_data': request_data}
            return jsonify(data), 201, response_headers
            
        elif request.method == 'PUT':
            # Handle PUT request
            request_data = request.get_json(silent=True)
            if request_data is None:
                return jsonify({'error': 'Invalid JSON data'}), 400, response_headers
            
            data = {'message': 'PUT request processed successfully', 'received_data': request_data}
            return jsonify(data), 200, response_headers
            
        elif request.method == 'DELETE':
            # Handle DELETE request
            data = {'message': 'DELETE request processed successfully'}
            return jsonify(data), 200, response_headers
            
    except Exception as e:
        # Log error (in production, use proper logging)
        print(f"Error processing request: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500, response_headers